import{c as d,Q as c,j as o,m as i}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"База данных и сохраняемые данные","description":"","frontmatter":{},"headers":[],"relativePath":"ru/database.md","filePath":"ru/database.md","lastUpdated":1780017229000}'),a={name:"ru/database.md"};function l(t,e,r,s,n,p){return c(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="база-данных-и-сохраняемые-данные" tabindex="-1">База данных и сохраняемые данные <a class="header-anchor" href="#база-данных-и-сохраняемые-данные" aria-label="Permalink to &quot;База данных и сохраняемые данные&quot;">​</a></h1><p>Эта страница описывает текущую схему SQLite и метаданные/данные анализа, которые сохраняются в SQLite. Используйте её, чтобы понять, что именно сохраняет приложение, что удаляет сброс и почему тот или иной режим поиска сначала требует определённого прохода анализа.</p><h2 id="спецификация-sqlite" tabindex="-1">Спецификация SQLite <a class="header-anchor" href="#спецификация-sqlite" aria-label="Permalink to &quot;Спецификация SQLite&quot;">​</a></h2><p>Текущая версия схемы — <code>2</code>.</p><p>База данных — это локальное состояние пользователя. Обычные рабочие процессы сканирования, анализа, поиска, сброса, очистки и переноса библиотеки изменяют только записи в SQLite; они не перезаписывают аудиофайлы. Явным исключением является отдельный рабочий процесс записи жанровых тегов MAEST, описанный в разделе <a href="./search-and-tags.html">Поиск и запись тегов</a>.</p><h3 id="tracks" tabindex="-1"><code>tracks</code> <a class="header-anchor" href="#tracks" aria-label="Permalink to &quot;`tracks`&quot;">​</a></h3><p>Хранит по одной строке на каждый проиндексированный аудиофайл:</p><ul><li><code>id</code>: стабильный локальный идентификатор трека.</li><li><code>path</code>: уникальный сохранённый путь к аудиофайлу.</li><li><code>size</code>: размер файла на момент сканирования.</li><li><code>mtime</code>: время изменения файла на момент сканирования.</li><li><code>artist</code>, <code>title</code>, <code>album</code>: выбранные метаданные файла.</li><li><code>bpm</code>, <code>musical_key</code>, <code>energy</code>, <code>duration</code>: рабочие поля, используемые интерфейсом и процессами анализа.</li><li><code>metadata_json</code>: объект JSON для полей Mutagen и метаданных, полученных от моделей.</li><li><code>created_at</code>, <code>updated_at</code>: локальные временные метки строки.</li></ul><p><code>metadata_json</code> должен быть корректным JSON. В схеме есть триггеры, которые отклоняют некорректный JSON при вставке или обновлении.</p><p>Используйте эту таблицу, чтобы ответить на вопросы «какие треки есть в библиотеке?» и «какие метаданные или сводки анализа интерфейс показывает для строки?». Поле <code>path</code> — это ссылка обратно на локальный аудиофайл; перенос библиотеки обновляет этот сохранённый путь только тогда, когда те же файлы были перемещены в новый корневой каталог.</p><h3 id="embeddings" tabindex="-1"><code>embeddings</code> <a class="header-anchor" href="#embeddings" aria-label="Permalink to &quot;`embeddings`&quot;">​</a></h3><p>Хранит векторы моделей по треку и пространству embedding:</p><ul><li><code>track_id</code>: ссылается на <code>tracks.id</code>.</li><li><code>embedding_key</code>: в настоящее время <code>mert</code>, <code>clap</code> или <code>maest</code>.</li><li><code>model_name</code>: идентификатор модели или контрольной точки.</li><li><code>dim</code>: размерность вектора.</li><li><code>vector</code>: бинарная полезная нагрузка вектора float32.</li><li><code>updated_at</code>: локальная временная метка строки.</li></ul><p>Первичный ключ — <code>(track_id, embedding_key)</code>, поэтому один и тот же трек может иметь векторы MERT, CLAP и MAEST без смешивания этих пространств.</p><p>Используйте эту таблицу, чтобы проверить, достаточно ли данных для рабочего процесса на основе embedding: поиску MERT нужен <code>mert</code>, текстовому поиску CLAP нужен <code>clap</code>, а продвинутым combined-классификаторам нужны <code>mert</code> и <code>maest</code> вместе с признаками Sonara.</p><h3 id="library-settings" tabindex="-1"><code>library_settings</code> <a class="header-anchor" href="#library-settings" aria-label="Permalink to &quot;`library_settings`&quot;">​</a></h3><p>Хранит локальные настройки уровня базы данных, например выбранный корневой каталог музыки.</p><p>Используйте эту таблицу для предпочтений уровня приложения, привязанных к одной базе данных, а не к отдельному треку.</p><h3 id="track-likes" tabindex="-1"><code>track_likes</code> <a class="header-anchor" href="#track-likes" aria-label="Permalink to &quot;`track_likes`&quot;">​</a></h3><p>Хранит локальный список понравившихся треков:</p><ul><li><code>track_id</code>: ссылается на <code>tracks.id</code>.</li><li><code>liked_at</code>: локальная временная метка последнего действия «лайк».</li></ul><p>Первичный ключ — <code>track_id</code>, поэтому трек либо отмечен лайком, либо нет. Строки удаляются автоматически, когда соответствующий трек удаляется из локальной базы данных библиотеки. Лайки — это только состояние приложения; они никогда не записываются в аудиофайлы или теги Mutagen.</p><h3 id="track-classifier-scores" tabindex="-1"><code>track_classifier_scores</code> <a class="header-anchor" href="#track-classifier-scores" aria-label="Permalink to &quot;`track_classifier_scores`&quot;">​</a></h3><p>Хранит производные выходные данные классификатора по треку и ключу классификатора:</p><ul><li><code>track_id</code>: ссылается на <code>tracks.id</code>.</li><li><code>classifier</code>: ключ классификатора, например <code>live_instrumentation</code>.</li><li><code>score</code>: основная оценка, видимая пользователю и используемая для фильтрации.</li><li><code>label</code>: укрупнённая метка, например <code>high</code>, <code>medium</code> или <code>low</code>.</li><li><code>confidence</code>: максимальная вероятность класса.</li><li><code>probabilities_json</code>: вероятности классификатора по обучающим меткам профиля.</li><li><code>feature_set</code>: семейство признаков, используемое артефактом классификатора, в настоящее время <code>combined</code>.</li><li><code>model_id</code>: путь к продвинутой модели, использованной для оценки.</li><li><code>analyzed_at</code>: локальная временная метка оценки.</li></ul><p>Первичный ключ — <code>(track_id, classifier)</code>, поэтому повторный запуск классификатора обновляет оценку для этого трека, а не добавляет исторические строки.</p><p>Используйте эту таблицу, когда фильтр CLASS ведёт себя не так, как ожидается. Отсутствующие строки обычно означают, что продвинутый классификатор ещё не оценил трек или что у трека не было необходимых входных данных Sonara, MERT или MAEST во время оценки.</p><h2 id="метаданные-и-данные-анализа" tabindex="-1">Метаданные и данные анализа <a class="header-anchor" href="#метаданные-и-данные-анализа" aria-label="Permalink to &quot;Метаданные и данные анализа&quot;">​</a></h2><p>Приложение намеренно разделяет теги файлов и вычисляемые значения.</p><p>Сканирование Mutagen читает следующий фиксированный список (whitelist):</p><ul><li><code>artist</code></li><li><code>title</code></li><li><code>album</code></li><li><code>genre</code></li><li><code>year</code></li><li><code>country</code></li><li><code>label</code></li><li><code>catalog_number</code></li><li><code>track_number</code></li><li><code>disc_number</code></li><li><code>bpm</code></li><li><code>key</code></li><li><code>comment</code></li><li><code>isrc</code></li><li><code>duration</code></li><li><code>audio_format</code></li><li><code>audio_codec</code></li><li><code>date</code></li></ul><p>Значения нормализуются в JSON-безопасные значения перед сохранением. Специфичные для Mutagen объекты, такие как временные метки ID3, преобразуются в строки.</p><p><code>RefreshTags</code> заменяет только это подмножество метаданных Mutagen. Он сохраняет сохранённые пути и данные анализа моделей.</p><p>Выходные данные анализа находятся рядом с тегами файлов, а не заменяют их. Именно поэтому трек может одновременно показывать метаданные файла, такие как <code>genre</code> или <code>bpm</code>, и вычисляемые значения, такие как BPM от Sonara, жанры MAEST, embeddings или оценки классификаторов.</p>',34)])])}const _=d(a,[["render",l]]);export{u as __pageData,_ as default};
